import StatCard from "../components/ui/StartCard";

const AdminDashboard = ({ rooms, students }) => {
  const totalRooms = rooms.length;
  const occupiedRooms = rooms.filter(r => r.occupants.length > 0).length;
  const totalStudents = students.length;
  const assignedStudents = students.filter(s => s.roomId).length;

  return (
    <div>
      <h2 style={{ margin: "0 0 24px", fontSize: 22, fontWeight: 700, color: "#1e293b" }}>Dashboard</h2>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))", gap: 20, marginBottom: 32 }}>
        <StatCard label="Total Rooms" value={totalRooms} icon="bed" color="#3b82f6" />
        <StatCard label="Occupied Rooms" value={occupiedRooms} icon="check" color="#10b981" />
        <StatCard label="Total Students" value={totalStudents} icon="users" color="#6366f1" />
        <StatCard label="Assigned Students" value={assignedStudents} icon="award" color="#f59e0b" />
      </div>

      <div style={{ background: "#fff", borderRadius: 16, padding: 24, boxShadow: "0 2px 16px rgba(30,41,59,0.07)" }}>
        <h3 style={{ margin: "0 0 16px", fontSize: 16, fontWeight: 700, color: "#1e293b" }}>Room Overview</h3>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(160px, 1fr))", gap: 12 }}>
          {rooms.map(room => (
            <div key={room.id} style={{
              padding: "14px 16px", borderRadius: 12, border: "1.5px solid",
              borderColor: room.occupants.length >= room.capacity ? "#fca5a5" : "#bbf7d0",
              background: room.occupants.length >= room.capacity ? "#fff1f2" : "#f0fdf4"
            }}>
              <div style={{ fontWeight: 700, fontSize: 15, color: "#1e293b" }}>Room {room.id}</div>
              <div style={{ fontSize: 12, color: "#64748b", marginTop: 4 }}>{room.type}</div>
              <div style={{ fontSize: 13, marginTop: 8, fontWeight: 600, color: room.occupants.length >= room.capacity ? "#dc2626" : "#16a34a" }}>
                {room.occupants.length}/{room.capacity} occupied
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
